import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import Header from '../components/Header';
import { useAuth } from '../contexts/AuthContext';
import { registerUser } from '../services/api';
import './Register.css';

const Register = () => {
  const navigate = useNavigate();
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [agreement, setAgreement] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (!agreement) {
      setError('Необходимо принять условия использования');
      return;
    }

    if (formData.password !== formData.confirmPassword) {
      setError('Пароли не совпадают');
      return;
    }

    if (formData.password.length < 6) {
      setError('Пароль должен содержать минимум 6 символов');
      return;
    }

    try {
      const result = await registerUser({
        username: formData.username,
        email: formData.email,
        password: formData.password
      });

      if (result.success) {
        setSuccess('Регистрация прошла успешно! Перенаправляем...');
        login(result.user);

        setTimeout(() => {
          navigate('/');
        }, 2000);
      } else {
        setError(result.error || 'Ошибка при регистрации');
      }
    } catch (err) {
      setError(err.error || 'Ошибка при регистрации');
    }
  };

  return (
    <>
      <Header />
      <main className="register-container">
        <div className="register-card">
          <div className="register-header">
            <h1>СОЗДАТЬ АККАУНТ</h1>
            <p>Присоединяйтесь к MirarKino</p>
          </div>

          {error && <div className="error-message show">{error}</div>}
          {success && <div className="success-message show">{success}</div>}

          <form className="register-form" onSubmit={handleSubmit}>
            <div className="form-group">
              <label htmlFor="username">Имя пользователя</label>
              <input
                type="text"
                id="username"
                name="username"
                value={formData.username}
                onChange={handleChange}
                placeholder="Введите имя"
                required
                minLength="3"
                maxLength="20"
              />
            </div>

            <div className="form-group">
              <label htmlFor="email">Email</label>
              <input
                type="email"
                id="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                placeholder="your@email.com"
                required
              />
            </div>

            <div className="form-group">
              <label htmlFor="password">Пароль</label>
              <input
                type="password"
                id="password"
                name="password"
                value={formData.password}
                onChange={handleChange}
                placeholder="••••••••"
                required
                minLength="6"
              />
              <div className="password-requirements">
                • минимум 6 символов<br />
                • хотя бы одна цифра<br />
                • хотя бы одна заглавная буква
              </div>
            </div>

            <div className="form-group">
              <label htmlFor="confirm_password">Подтверждение пароля</label>
              <input
                type="password"
                id="confirm_password"
                name="confirmPassword"
                value={formData.confirmPassword}
                onChange={handleChange}
                placeholder="••••••••"
                required
              />
            </div>

            <div className="form-group checkbox-group">
              <input
                type="checkbox"
                id="agreement"
                checked={agreement}
                onChange={(e) => setAgreement(e.target.checked)}
                required
              />
              <label htmlFor="agreement">
                Я принимаю <a href="#">условия использования</a> и <a href="#">политику конфиденциальности</a>
              </label>
            </div>

            <button type="submit" className="register-submit">
              ЗАРЕГИСТРИРОВАТЬСЯ
            </button>
          </form>

          <div className="register-footer">
            Уже есть аккаунт?
            <Link to="/">Войти</Link>
          </div>
        </div>
      </main>
    </>
  );
};

export default Register;
